document.addEventListener("DOMContentLoaded",()=>{let e=document.querySelectorAll(".phone-button"),t=document.getElementById("main-display"),o=document.getElementById("story-display"),n=document.getElementById("story-text"),i=document.getElementById("bird-image"),a=document.getElementById("close-story"),s=document.getElementById("audio-player"),m=document.getElementById("progress"),d=document.getElementById("time-display"),l=document.querySelector(".pigeon-box"),p={1:{name:"Pigeon",text:"I used to carry secret messages across the front lines. Now I just hang out near the subway for crumbs.",img:"https://images.unsplash.com/photo-1514823197305-16c58a8ef756?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3"},2:{name:"Owl",text:"Everyone thinks I am wise. Honestly, I just have very large eyes and a high neck rotation.",img:"https://images.unsplash.com/photo-1543549732-230fe5d83c4c?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3"},3:{name:"Duck",text:"The pond is fine, but have you ever tried a heated pool? Absolute game changer.",img:"https://images.unsplash.com/photo-1459156212016-c812468e2115?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-3.mp3"},4:{name:"Chick",text:"I just got here. Why is everything so big? And why do people keep making high-pitched noises at me?",img:"https://images.unsplash.com/photo-1548550023-2bdb3c5beed7?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-4.mp3"},5:{name:"Swan",text:"Elegant? Yes. But if you come near my nest, I will remind you that I am basically a dinosaur in a fancy suit.",img:"https://images.unsplash.com/photo-1516734212186-a967f81ad0d7?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-5.mp3"},6:{name:"Raven",text:'Nevermore? More like "Whatevermore". I am actually quite optimistic for a bird.',img:"https://images.unsplash.com/photo-1445108771252-d1cc31a02a3c?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-6.mp3"},7:{name:"Eagle",text:"The view from up here is incredible. But finding a decent parking spot for a nest? Nightmare.",img:"https://images.unsplash.com/photo-1481137344492-d5a0bb92f972?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-7.mp3"},8:{name:"Parrot",text:"I can speak three languages and I still get paid in sunflower seeds. My agent is a bird-brain.",img:"https://images.unsplash.com/photo-1522858547137-f1dcec554f55?w=200&h=200&fit=crop",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3"},9:{name:"Avian Influenza",text:"A collective of bird-inspired lunatics. Matteo Cancellieri, Tony Gee, David Pride",audio:"https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3"}};e.forEach(e=>{e.addEventListener("click",()=>{let a,m=e.getAttribute("data-key");p[m]&&(s.src=(a=p[m]).audio,s.play().catch(e=>console.warn("Play blocked",e)),n.textContent=a.text,i.style.backgroundImage=`url(${a.img})`,l.classList.add("hidden"),o.classList.remove("hidden"),t.classList.add("spinning"))})}),s.addEventListener("timeupdate",()=>{let e=s.currentTime/s.duration*100;m.style.width=`${e}%`;let t=Math.floor(s.currentTime/60),o=Math.floor(s.currentTime%60).toString().padStart(2,"0");d.textContent=`${t}:${o}`}),a.addEventListener("click",()=>{s.pause(),s.currentTime=0,o.classList.add("hidden"),l.classList.remove("hidden"),t.classList.remove("spinning")}),s.addEventListener("ended",()=>{t.classList.remove("spinning")})});
